css:
@page {
  size: A4; margin: 20mm 20mm 26mm 20mm;
  @bottom-left { content: "Beispiel Handels GmbH · Marktplatz 1 · 10115 Berlin \A Amtsgericht Charlottenburg · HRB 123456 \A Geschäftsführer: Max Beispiel"; font-size: 6.5pt; line-height: 1.45; color: #8a8a8a; white-space: pre-line; vertical-align: top; padding-top: 4mm; }
  @bottom-center { content: "Seite " counter(page) " von " counter(pages); font-size: 6.5pt; color: #8a8a8a; white-space: nowrap; vertical-align: top; padding-top: 4mm; }
  @bottom-right { content: "USt-IdNr. DE123456789 · St.-Nr. 13/456/78901 \A IBAN DE89 3704 0044 0532 0130 00 · BIC COBADEFFXXX"; font-size: 6.5pt; line-height: 1.45; color: #8a8a8a; white-space: pre-line; text-align: right; vertical-align: top; padding-top: 4mm; }
}

body { color: #0b0b0f; font-family: 'Helvetica', 'Arial', sans-serif; }
.num { font-variant-numeric: tabular-nums; }

/* Header */
.doc-header { display: block; margin: 0; }
.me-head { display: flex; align-items: center; justify-content: space-between; }
.me-head__brand { display: flex; align-items: center; gap: 3.5mm; }
.me-mark { height: 11mm; width: 11mm; display: block; }
.me-brandname { font-size: 12pt; font-weight: 700; letter-spacing: -0.01em; }
.me-head__doc { text-align: right; }
.me-eyebrow { display: block; font-size: 8pt; letter-spacing: 0.32em; text-transform: uppercase; color: #5b53ff; font-weight: 700; }
.me-docno { display: block; font-size: 15pt; font-weight: 700; letter-spacing: -0.01em; margin-top: 1mm; }

.me-rule { height: 2px; background: #5b53ff; margin: 7mm 0 8mm; width: 28mm; border-radius: 2px; }

.me-meta { display: flex; gap: 7mm; margin-bottom: 11mm; }
.me-meta__col { flex: 1 1 0; min-width: 0; }
.me-meta__col--to { flex: 1.5 1 0; }
.me-meta__col--amount { flex: 0 0 42mm; }
.me-meta__col > div { line-height: 1.5; }
.me-meta__label { display: block; font-size: 7pt; letter-spacing: 0.18em; text-transform: uppercase; color: #9499a3; font-weight: 600; margin-bottom: 1.6mm; }
.me-meta__label--mt { margin-top: 4.5mm; }
.me-meta__strong { font-weight: 700; }
.me-amount { font-size: 19pt; font-weight: 700; letter-spacing: -0.02em; font-variant-numeric: tabular-nums; margin-bottom: 2.5mm; }
.me-chip { display: inline-block; font-size: 7.5pt; font-weight: 600; letter-spacing: 0.04em; text-transform: uppercase; color: #b45309; background: #fef3c7; border-radius: 999px; padding: 1mm 3mm; }

.me-items { width: 100%; border-collapse: collapse; margin-bottom: 9mm; }
.me-items thead th { font-size: 7pt; letter-spacing: 0.16em; text-transform: uppercase; color: #9499a3; font-weight: 600; text-align: left; padding: 0 0 2.5mm; border-bottom: 1px solid #1a1a22; }
.me-items tbody td { padding: 3.4mm 0; border-bottom: 1px solid #ededf0; vertical-align: top; }
.me-c-pos { width: 12mm; color: #b6bac2; font-variant-numeric: tabular-nums; }
.me-c-qty { width: 24mm; text-align: right; }
.me-c-price { width: 30mm; text-align: right; color: #4b5563; }
.me-c-total { width: 32mm; text-align: right; font-weight: 700; }
.me-c-desc strong { font-weight: 700; }
.me-desc { display: block; color: #6b7280; font-size: 9pt; margin-top: 0.6mm; }
.me-sku { display: block; color: #b6bac2; font-size: 8pt; letter-spacing: 0.04em; margin-top: 0.6mm; }
thead th.me-c-qty, thead th.me-c-price, thead th.me-c-total { text-align: right; }

.me-foot { display: flex; justify-content: space-between; gap: 14mm; align-items: flex-start; }
.me-pay { flex: 1 1 0; }
.me-pay__grid { display: grid; grid-template-columns: 26mm 1fr; gap: 1mm 4mm; margin: 2mm 0 0; font-size: 9.5pt; }
.me-pay__grid dt { color: #9499a3; }
.me-pay__grid dd { margin: 0; font-variant-numeric: tabular-nums; }
.me-totals { flex: 0 0 72mm; }
.me-trow { display: flex; justify-content: space-between; padding: 2mm 0; font-size: 10pt; }
.me-trow span:first-child { color: #4b5563; }
.me-trow--grand { margin-top: 1.5mm; padding-top: 3.5mm; border-top: 2px solid #1a1a22; font-size: 13pt; font-weight: 700; }
.me-trow--grand span:first-child { color: #0b0b0f; }
.me-trow--grand .num { color: #5b53ff; }

.me-note { margin-top: 11mm; padding-top: 5mm; border-top: 1px solid #ededf0; color: #6b7280; font-size: 9pt; max-width: 120mm; }
